import os
import json
import argparse

import torch
import torch.nn as nn
from torch.utils.data import Dataset, DataLoader
from torchvision import transforms
from PIL import Image
from transformers import CLIPModel

from model import CLIP_MEAN, CLIP_STD, NUM_CLASSES, FEATURE_DIM


class ImageListDataset(Dataset):
    def __init__(self, data_path, split='test'):
        split_file = os.path.join(data_path, f'{split}.txt')
        with open(split_file, 'r') as f:
            rows = [line.strip().split() for line in f if line.strip()]
        self.files = [r[0] for r in rows]
        self.data_path = data_path
        self.transform = transforms.Compose([
            transforms.ToTensor(),
            transforms.Normalize(CLIP_MEAN, CLIP_STD),
        ])

    def __len__(self):
        return len(self.files)

    def __getitem__(self, idx):
        img = Image.open(os.path.join(self.data_path, 'images', self.files[idx])).convert('RGB')
        return self.transform(img)


class LinearHead(nn.Module):
    def __init__(self, in_dim=FEATURE_DIM, num_classes=NUM_CLASSES):
        super().__init__()
        self.fc = nn.Linear(in_dim, num_classes)

    def forward(self, x):
        return self.fc(x)


class MLPHead(nn.Module):
    def __init__(self, in_dim=FEATURE_DIM, hidden_dim=1024, num_classes=NUM_CLASSES, dropout=0.2):
        super().__init__()
        self.net = nn.Sequential(
            nn.Linear(in_dim, hidden_dim),
            nn.GELU(),
            nn.Dropout(dropout),
            nn.Linear(hidden_dim, num_classes),
        )

    def forward(self, x):
        return self.net(x)


class FullCLIPLinearClassifier(nn.Module):
    def __init__(self, num_classes=NUM_CLASSES):
        super().__init__()
        self.clip = CLIPModel.from_pretrained('openai/clip-vit-base-patch16')
        self.classifier = nn.Linear(FEATURE_DIM, num_classes)

    def forward(self, x):
        vision_out = self.clip.vision_model(pixel_values=x, return_dict=True)
        pooled = vision_out.pooler_output
        feats = self.clip.visual_projection(pooled)
        feats = feats / feats.norm(dim=-1, keepdim=True).clamp_min(1e-6)
        return self.classifier(feats)


class FullCLIPMLPClassifier(nn.Module):
    def __init__(self, hidden_dim=1024, dropout=0.2):
        super().__init__()
        self.clip = CLIPModel.from_pretrained('openai/clip-vit-base-patch16')
        self.classifier = nn.Sequential(
            nn.Linear(FEATURE_DIM, hidden_dim),
            nn.GELU(),
            nn.Dropout(dropout),
            nn.Linear(hidden_dim, NUM_CLASSES),
        )

    def forward(self, x):
        vision_out = self.clip.vision_model(pixel_values=x, return_dict=True)
        pooled = vision_out.pooler_output
        feats = self.clip.visual_projection(pooled)
        feats = feats / feats.norm(dim=-1, keepdim=True).clamp_min(1e-6)
        return self.classifier(feats)


@torch.no_grad()
def safe_clip_features(clip_model, x):
    vision_out = clip_model.vision_model(pixel_values=x, return_dict=True)
    pooled = vision_out.pooler_output
    feats = clip_model.visual_projection(pooled)
    feats = feats / feats.norm(dim=-1, keepdim=True).clamp_min(1e-6)
    return feats


def _extract_state_dict(ckpt):
    if isinstance(ckpt, dict):
        for key in ['state_dict', 'model_state_dict', 'model']:
            if key in ckpt and isinstance(ckpt[key], dict):
                return ckpt[key]
    return ckpt


def _strip_prefixes(state_dict):
    out = {}
    for k, v in state_dict.items():
        nk = k
        changed = True
        while changed:
            changed = False
            for prefix in ['module.', 'model.']:
                if nk.startswith(prefix):
                    nk = nk[len(prefix):]
                    changed = True
        out[nk] = v
    return out


def build_model_from_checkpoint(ckpt, device):
    state_dict = _strip_prefixes(_extract_state_dict(ckpt))
    keys = set(state_dict.keys())

    if 'fc.weight' in keys and 'fc.bias' in keys:
        clip = CLIPModel.from_pretrained('openai/clip-vit-base-patch16').to(device)
        clip.eval()
        head = LinearHead().to(device)
        head.load_state_dict({'fc.weight': state_dict['fc.weight'], 'fc.bias': state_dict['fc.bias']}, strict=True)
        head.eval()
        return 'cached_linear', (clip, head)

    if 'net.0.weight' in keys and 'net.0.bias' in keys and 'net.3.weight' in keys and 'net.3.bias' in keys:
        clip = CLIPModel.from_pretrained('openai/clip-vit-base-patch16').to(device)
        clip.eval()
        hidden_dim = state_dict['net.0.weight'].shape[0]
        head = MLPHead(hidden_dim=hidden_dim).to(device)
        head.load_state_dict({
            'net.0.weight': state_dict['net.0.weight'],
            'net.0.bias': state_dict['net.0.bias'],
            'net.3.weight': state_dict['net.3.weight'],
            'net.3.bias': state_dict['net.3.bias'],
        }, strict=False)
        head.eval()
        return 'cached_mlp', (clip, head)

    if 'weight' in keys and 'bias' in keys and state_dict['weight'].ndim == 2:
        clip = CLIPModel.from_pretrained('openai/clip-vit-base-patch16').to(device)
        clip.eval()
        head = LinearHead(in_dim=state_dict['weight'].shape[1], num_classes=state_dict['weight'].shape[0]).to(device)
        head.fc.weight.data.copy_(state_dict['weight'])
        head.fc.bias.data.copy_(state_dict['bias'])
        head.eval()
        return 'cached_linear', (clip, head)

    clip_keys = [k for k in keys if k.startswith('clip.')]
    if clip_keys:
        remap = {}
        for k, v in state_dict.items():
            remap[k] = v

        if 'classifier.weight' in remap and 'classifier.bias' in remap:
            model = FullCLIPLinearClassifier(num_classes=remap['classifier.weight'].shape[0]).to(device)
            model.load_state_dict(remap, strict=False)
            model.eval()
            return 'full_model', model

        if 'classifier.0.weight' in remap and remap['classifier.0.weight'].ndim == 2:
            hidden_dim = remap['classifier.0.weight'].shape[0]
            model = FullCLIPMLPClassifier(hidden_dim=hidden_dim).to(device)
            model.load_state_dict(remap, strict=False)
            model.eval()
            return 'full_model', model

        if 'classifier.0.bias' in remap and remap['classifier.0.bias'].ndim == 1 and remap['classifier.0.bias'].shape[0] == FEATURE_DIM and 'classifier.1.weight' in remap:
            model = FullCLIPLinearClassifier(num_classes=remap['classifier.1.weight'].shape[0]).to(device)
            translated = {}
            for k, v in remap.items():
                if k == 'classifier.1.weight':
                    translated['classifier.weight'] = v
                elif k == 'classifier.1.bias':
                    translated['classifier.bias'] = v
                elif not k.startswith('classifier.0'):
                    translated[k] = v
            model.load_state_dict(translated, strict=False)
            model.eval()
            return 'full_model', model

    raise RuntimeError(f'Unsupported checkpoint format. Sample keys: {sorted(list(keys))[:20]}')


@torch.no_grad()
def predict_cached(model_tuple, loader, device):
    clip, head = model_tuple
    preds = []
    for x in loader:
        x = x.to(device, non_blocking=True)
        feats = safe_clip_features(clip, x)
        logits = head(feats)
        preds.extend(logits.argmax(dim=1).cpu().tolist())
    return preds


@torch.no_grad()
def predict_full(model, loader, device):
    preds = []
    for x in loader:
        x = x.to(device, non_blocking=True)
        logits = model(x)
        preds.extend(logits.argmax(dim=1).cpu().tolist())
    return preds


def main():
    parser = argparse.ArgumentParser()
    parser.add_argument('--data_path', type=str, required=True)
    parser.add_argument('--checkpoint', type=str, required=True)
    parser.add_argument('--output', type=str, required=True)
    parser.add_argument('--batch_size', type=int, default=128)
    parser.add_argument('--num_workers', type=int, default=8)
    args = parser.parse_args()

    split = 'test' if os.path.exists(os.path.join(args.data_path, 'test.txt')) else 'val'
    ds = ImageListDataset(args.data_path, split=split)
    loader = DataLoader(ds, batch_size=args.batch_size, shuffle=False, num_workers=args.num_workers, pin_memory=True)

    device = torch.device('cuda' if torch.cuda.is_available() else 'cpu')
    ckpt = torch.load(args.checkpoint, map_location='cpu')
    mode, model_obj = build_model_from_checkpoint(ckpt, device)

    if mode.startswith('cached_'):
        preds = predict_cached(model_obj, loader, device)
    else:
        preds = predict_full(model_obj, loader, device)

    with open(args.output, 'w') as f:
        json.dump({'predictions': [int(x) for x in preds]}, f)


if __name__ == '__main__':
    main()
